import { useState, useRef } from 'react';
import {
    Box,
    Button,
    Grid,
    Typography,
    IconButton,
    Card,
    CardMedia,
    Divider,
    Paper
} from '@mui/material';
import {
    Add as AddIcon,
    Delete as DeleteIcon,
    AddPhotoAlternate as AddPhotoIcon
} from '@mui/icons-material';
import PhotoBookPage from './PhotoBookPage';

const PhotoBookPages = ({ format, availablePhotos, pages, onPagesChange, onPhotosAdd }) => {
    const [selectedPhotos, setSelectedPhotos] = useState([]);
    const fileInputRef = useRef(null);

    const handleAddSpread = () => {
        // Добавляем разворот (две страницы)
        onPagesChange([
            ...pages,
            { 
                spreadId: pages.length / 2,
                leftPage: { photos: [] },
                rightPage: { photos: [] }
            }
        ]);
    };

    const handleDeleteSpread = (spreadIndex) => {
        const newPages = pages.filter((_, index) => index !== spreadIndex);
        onPagesChange(newPages);
    };

    const handleFileSelect = (event) => {
        const files = Array.from(event.target.files);
        if (files.length > 0) {
            onPhotosAdd(files);
        }
        // Очищаем input для возможности повторной загрузки тех же файлов
        event.target.value = '';
    };

    const handlePhotoAdd = (spreadIndex, isRightPage, position, photo) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            targetPage.photos = [
                ...targetPage.photos.filter(p => p.position !== position),
                { ...photo, position }
            ];
            onPagesChange(newPages);
            setSelectedPhotos(prev => [...prev, photo.id]);
        }
    };

    const handlePhotoRemove = (spreadIndex, isRightPage, position) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            const removedPhoto = targetPage.photos.find(p => p.position === position);
            if (removedPhoto) {
                setSelectedPhotos(prev => prev.filter(id => id !== removedPhoto.id));
            }
            targetPage.photos = targetPage.photos.filter(p => p.position !== position);
            onPagesChange(newPages);
        }
    };

    const handlePhotoEdit = (spreadIndex, isRightPage, position, editedPhoto) => {
        const newPages = [...pages];
        const spread = newPages[spreadIndex];
        if (spread) {
            const targetPage = isRightPage ? spread.rightPage : spread.leftPage;
            const photoIndex = targetPage.photos.findIndex(p => p.position === position);
            if (photoIndex !== -1) {
                targetPage.photos[photoIndex] = {
                    ...targetPage.photos[photoIndex],
                    ...editedPhoto
                };
                onPagesChange(newPages);
            }
        }
    };

    return (
        <Box sx={{ width: '100%', p: 2 }}>
            <Box sx={{ mb: 4 }}>
                <Typography variant="h5" gutterBottom align="center">
                    Создание страниц фотокниги
                </Typography>
                <Typography variant="subtitle1" color="text.secondary" gutterBottom align="center">
                    Перетащите фотографии на страницы
                </Typography>
            </Box>

            <Grid container spacing={2} sx={{ height: '100%' }}>
                {/* Панель с доступными фотографиями */}
                <Grid item xs={12} md={3} sx={{ 
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column'
                }}>
                    <Typography variant="h6" gutterBottom>
                        Доступные фотографии
                    </Typography>
                    <Box sx={{ 
                        flex: 1,
                        display: 'grid',
                        gridTemplateColumns: 'repeat(2, 80px)',
                        justifyContent: 'center',
                        gap: 1,
                        overflowY: 'auto',
                        p: 1,
                        border: '1px solid #eee',
                        borderRadius: 1,
                        bgcolor: 'background.paper',
                        '&::-webkit-scrollbar': {
                            width: 6,
                            bgcolor: 'background.paper'
                        },
                        '&::-webkit-scrollbar-thumb': {
                            borderRadius: 2,
                            bgcolor: 'grey.300'
                        }
                    }}>
                        {/* Кнопка добавления фотографий */}
                        <Card
                            sx={{
                                width: 80,
                                height: 80,
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                cursor: 'pointer',
                                border: '2px dashed',
                                borderColor: 'grey.300',
                                bgcolor: 'background.paper',
                                transition: 'all 0.2s ease-in-out',
                                '&:hover': {
                                    borderColor: 'primary.main',
                                    bgcolor: 'action.hover',
                                    transform: 'scale(1.05)',
                                }
                            }}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <AddPhotoIcon sx={{ fontSize: 32, color: 'grey.500' }} />
                            <input
                                ref={fileInputRef}
                                type="file"
                                multiple
                                accept="image/*"
                                style={{ display: 'none' }}
                                onChange={handleFileSelect}
                            />
                        </Card>

                        {/* Миниатюры фотографий */}
                        {availablePhotos
                            .filter(photo => !selectedPhotos.includes(photo.id))
                            .map((photo) => (
                                <Card
                                    key={photo.id}
                                    sx={{
                                        width: 80,
                                        height: 80,
                                        cursor: 'grab',
                                        transition: 'all 0.2s ease-in-out',
                                        '&:hover': {
                                            boxShadow: 3,
                                            transform: 'scale(1.05)',
                                            zIndex: 1
                                        },
                                        '&:active': {
                                            cursor: 'grabbing'
                                        }
                                    }}
                                    draggable
                                    onDragStart={(e) => {
                                        e.dataTransfer.setData('photo', JSON.stringify(photo));
                                    }}
                                >
                                    <CardMedia
                                        component="img"
                                        image={photo.preview || photo.url}
                                        alt={`Photo ${photo.id}`}
                                        sx={{
                                            width: '100%',
                                            height: '100%',
                                            objectFit: 'cover'
                                        }}
                                    />
                                </Card>
                            ))}
                    </Box>
                </Grid>

                {/* Область разворотов */}
                <Grid item xs={12} md={9} sx={{ 
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column'
                }}>
                    <Box sx={{ 
                        flex: 1,
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        gap: 4,
                        overflowY: 'auto',
                        p: 4,
                        bgcolor: 'grey.100',
                        '&::-webkit-scrollbar': {
                            width: 8,
                            bgcolor: 'background.paper'
                        },
                        '&::-webkit-scrollbar-thumb': {
                            borderRadius: 2,
                            bgcolor: 'grey.300'
                        }
                    }}>
                        {/* Контейнер для разворотов */}
                        <Box sx={{
                            display: 'flex',
                            flexDirection: 'column',
                            gap: 4,
                            width: '100%',
                            maxWidth: 900,
                            alignItems: 'center'
                        }}>
                            {pages.map((spread, spreadIndex) => (
                                <Paper
                                    key={spreadIndex}
                                    elevation={3}
                                    sx={{ 
                                        position: 'relative',
                                        display: 'flex',
                                        flexDirection: 'row',
                                        p: 3,
                                        bgcolor: 'background.paper',
                                        borderRadius: 2,
                                        width: '100%',
                                        justifyContent: 'center',
                                        gap: 2
                                    }}
                                >
                                    {/* Левая страница */}
                                    <Box sx={{ 
                                        width: format.size === '20×20' ? 400 : format.size === '30×30' ? 500 : 600,
                                        height: format.size === '20×20' ? 400 : format.size === '30×30' ? 500 : 600,
                                        border: '1px solid',
                                        borderColor: 'grey.300',
                                        borderRadius: 1,
                                        overflow: 'hidden',
                                        bgcolor: 'common.white'
                                    }}>
                                        <PhotoBookPage
                                            format={format}
                                            photos={spread.leftPage.photos}
                                            onPhotoAdd={(position, photo) => handlePhotoAdd(spreadIndex, false, position, photo)}
                                            onPhotoRemove={(position) => handlePhotoRemove(spreadIndex, false, position)}
                                            onPhotoEdit={(position, photo) => handlePhotoEdit(spreadIndex, false, position, photo)}
                                        />
                                    </Box>

                                    {/* Разделитель между страницами */}
                                    <Box sx={{
                                        width: 40,
                                        display: 'flex',
                                        flexDirection: 'column',
                                        justifyContent: 'center',
                                        alignItems: 'center'
                                    }}>
                                        <Divider orientation="vertical" flexItem sx={{ 
                                            height: '100%',
                                            borderRightWidth: 2,
                                            borderColor: 'grey.300'
                                        }} />
                                    </Box>

                                    {/* Правая страница */}
                                    <Box sx={{ 
                                        width: format.size === '20×20' ? 400 : format.size === '30×30' ? 500 : 600,
                                        height: format.size === '20×20' ? 400 : format.size === '30×30' ? 500 : 600,
                                        border: '1px solid',
                                        borderColor: 'grey.300',
                                        borderRadius: 1,
                                        overflow: 'hidden',
                                        bgcolor: 'common.white'
                                    }}>
                                        <PhotoBookPage
                                            format={format}
                                            photos={spread.rightPage.photos}
                                            onPhotoAdd={(position, photo) => handlePhotoAdd(spreadIndex, true, position, photo)}
                                            onPhotoRemove={(position) => handlePhotoRemove(spreadIndex, true, position)}
                                            onPhotoEdit={(position, photo) => handlePhotoEdit(spreadIndex, true, position, photo)}
                                        />
                                    </Box>

                                    {spreadIndex > 0 && (
                                        <IconButton
                                            size="small"
                                            onClick={() => handleDeleteSpread(spreadIndex)}
                                            sx={{ 
                                                position: 'absolute',
                                                top: 8,
                                                right: 8,
                                                bgcolor: 'background.paper',
                                                boxShadow: 1,
                                                '&:hover': {
                                                    bgcolor: 'error.light',
                                                    color: 'common.white'
                                                }
                                            }}
                                        >
                                            <DeleteIcon />
                                        </IconButton>
                                    )}
                                </Paper>
                            ))}

                            {/* Кнопка добавления разворота */}
                            <Button
                                variant="outlined"
                                startIcon={<AddIcon />}
                                onClick={handleAddSpread}
                                sx={{ 
                                    width: 200,
                                    height: 50,
                                    borderStyle: 'dashed',
                                    borderWidth: 2,
                                    '&:hover': {
                                        borderStyle: 'dashed',
                                        borderWidth: 2,
                                    }
                                }}
                            >
                                Добавить разворот
                            </Button>
                        </Box>
                    </Box>
                </Grid>
            </Grid>
        </Box>
    );
};

export default PhotoBookPages;
